do $do$
declare
  gid uuid;
  hid uuid;
begin
  select id into gid from public.games where slug='call-of-dragons';
  select id into hid from public.heroes where game_id=gid and slug=$mbh$forondil$mbh$;
  delete from public.hero_builds where hero_id=hid;
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 0, $mbh$Ranking actual – ¿es Forondil S-Tier, A-Tier o D-Tier?$mbh$, $mbh$Mira cómo se posiciona Forondil en los distintos modos de juego de Call of Dragons en mi tier list actual aquí, y asegúrate también de estar jugando con la mejor facción de Call of Dragons o podrías afectar tu progreso de forma muy negativa — tengo una guía actualizada sobre las mejores facciones de Call of Dragons aquí.

¡Importante! No te pierdas Gemas, Llaves, Boosters y Speedups gratis y revisa con frecuencia mi lista de códigos de regalo activos para Call of Dragons aquí.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-forondil-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 1, $mbh$Orden de habilidades$mbh$, $mbh$$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-forondil-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 2, $mbh$Mejores tipos de tropa$mbh$, $mbh$Forondil es el primer héroe volador con Cavalry y esto es obvio en su caso: la mayor parte de su kit gira en torno a la Cavalry, así que asegúrate de llevar Cavalry con él. Y si juegas con la facción Springwardens tienes que usar la Cavalry voladora que tienen, y nada en el campo estará a salvo de ti.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-forondil-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 3, $mbh$Mejores parejas de héroe para Forondil$mbh$, $mbh$Theia es una muy buena pareja con Forondil ya que ambos son héroes voladores, tienen mucha sinergia y con Theia consigues el escudo y el aspecto de supervivencia que la Cavalry naturalmente echa un poco en falta (Ver build completa aquí).

Bakshi es la pareja con la que más me divertí, porque simplemente arrasan con todo y con Bakshi además tienes buffs de HP para hacer la marcha más resistente. En este caso, sin embargo, te recomiendo usar a Bakshi como comandante principal (Ver build completa aquí).

Theodore obviamente también es una buena elección ya que fueron lanzados juntos, ambos son de Cavalry y tienen una sólida sinergia, y creo que tendrán un gran impacto hacia las etapas más avanzadas de la temporada (Ver build completa aquí).

Emrys funciona y hace muchísimo daño con Forondil, pero el problema principal que tengo es que necesita ser atacado activamente para activar la rage extra, y muchas veces estarás cazando jugadores que huyen, así que no le sacarás mucho provecho a eso (Ver build completa aquí).

Ffraegar puede parecerte un poco rara en la lista, pero tiene buenos buffs y también es una héroe voladora, así que si no puedes usar las de arriba puede funcionar más o menos con Forondil (Ver build completa aquí).

Hosk no ofrece demasiadas sinergias, lo cual puede sonar raro porque es muy versátil, pero en este caso simplemente fue flojo en mis pruebas (Ver build completa aquí).

Kregg es un héroe volador pero para Marksman, y emparejarlos solo tiene sentido si tienes una necesidad desesperada de otro héroe volador para tu legión (Ver build completa aquí).

Alistair: la única sinergia real aquí es que ambos son héroes de Cavalry, pero no me divertí nada con ellos (Ver build completa aquí).$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-forondil-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 4, $mbh$Mejores artefactos$mbh$, $mbh$Veamos ahora los numerosos artefactos que podrías usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las estadísticas, pero sin importar qué artefactos tengas disponibles, encontrarás el que mejor funcione. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Oath of Stormpeak es un artefacto increíble para Forondil ya que tienes grandes estadísticas, gran daño y el efecto de ejecución es prácticamente todo lo que buscas, incluso cuando el enemigo huye (y con la velocidad de marcha no tienen ninguna oportunidad de todos modos). Kingslayer es un artefacto increíble para Forondil ya que tienes grandes estadísticas, gran daño y el efecto de ejecución es prácticamente todo lo que buscas, incluso cuando el enemigo huye (y con la velocidad de marcha no tienen ninguna oportunidad de todos modos).$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-forondil-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 5, $mbh$Mejores sinergias de mascota para Forondil (NUEVO)$mbh$, $mbh$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Forondil con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets de Call of Dragons aquí para ver cuáles valen la inversión en general.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-forondil-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 6, $mbh$Mejores builds para Forondil$mbh$, $mbh$Abajo encontrarás las builds de árbol de talentos para Forondil que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos + algo de contexto adicional para cada build de talentos que muy probablemente apreciarás. La build de talentos más moderna aquí con Forondil, donde realmente quieres meterte en el árbol de control para conseguir los buenos talentos de ahí tanto como sea posible. Puedes ajustar los nodos finales del árbol de control como quieras, son libres para mezclar y combinar, solo asegúrate de conseguir los nodos principales como se recomienda. Sinceramente, una build más anticuada aquí con él que solía ser mucho más popular en la época en que fue lanzado, y la verdad es que no la usaría en el meta actual, para nada.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-forondil-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 7, $mbh$Conclusión$mbh$, $mbh$Espero que esta guía para construir a Forondil te haya ayudado a invertir sin perder mucho tiempo ni recursos. Si te gustó o tienes más preguntas (o quizás también anotaciones que creas que deberían añadirse aquí en esta guía), no dudes en publicarlas abajo en la sección de comentarios. Gracias por leer y que tengas un gran día.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-forondil-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  select id into hid from public.heroes where game_id=gid and slug=$mbh$theodore$mbh$;
  delete from public.hero_builds where hero_id=hid;
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 0, $mbh$Ranking actual – ¿es Theodore S-Tier, A-Tier o D-Tier?$mbh$, $mbh$Mira cómo se posiciona Theodore en los distintos modos de juego de Call of Dragons en mi tier list actual aquí, y asegúrate también de estar jugando con la mejor facción de Call of Dragons o podrías afectar tu progreso de forma muy negativa — tengo una guía actualizada sobre las mejores facciones de Call of Dragons aquí.

¡Importante! No te pierdas Gemas, Llaves, Boosters y Speedups gratis y revisa con frecuencia mi lista de códigos de regalo activos para Call of Dragons aquí.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-theodore-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 1, $mbh$Orden de habilidades$mbh$, $mbh$$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-theodore-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 2, $mbh$Mejores tipos de tropa$mbh$, $mbh$Ya señalé arriba que tiene muy poco sentido usarlo como comandante de Garrison, así que mejor concéntrate en llevarlo con Cavalry por el mundo abierto y merodear por ahí; para esto funciona aún mejor.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-theodore-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 3, $mbh$Mejores parejas de héroe para Theodore$mbh$, $mbh$Emrys es una buena pareja por el simple hecho de que tiene una salida de daño brutal pero le cuesta la supervivencia, y con Theodore tienes eso además de que reduces el HP del objetivo, lo que ayuda a Emrys a rematar su daño rápidamente (Ver build completa aquí).

Forondil también funciona bien, pero siento que más bien quieres montarlo con un héroe que habilite mejor sus habilidades de lo que lo hace Theodore, y en ese caso correría a Forondil como comandante principal de la legión sin dudarlo (Ver build completa aquí).

Bakshi con Theodore (sin importar a cuál pongas como comandante de la legión) forma una legión de Cavalry muy resistente y tanque, y aunque sobre el papel van bien juntos, personalmente encuentro que la Cavalry tanque es algo raro y va en contra del arquetipo. Pero funcionan (Ver build completa aquí).

Alistair es solo un respaldo si no tienes otras opciones, ya que más allá de que ambos son de Cavalry no hay demasiada sinergia (Ver build completa aquí).$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-theodore-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 4, $mbh$Mejores artefactos$mbh$, $mbh$Veamos ahora los numerosos artefactos que podrías usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las estadísticas, pero sin importar qué artefactos tengas disponibles, encontrarás el que mejor funcione. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Kingslayer solo es viable SI usas a Theodore como comandante de Garrison, y eso es un gran SI. No te recomendaría hacer eso, pero si lo haces, querrás usar este artefacto. Breath of the Forest solo es viable SI usas a Theodore como comandante de Garrison, y eso es un gran SI. No te recomendaría hacer eso, pero si lo haces, querrás usar este artefacto.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-theodore-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 5, $mbh$Mejores sinergias de mascota para Theodore (NUEVO)$mbh$, $mbh$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Theodore con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets de Call of Dragons aquí para ver cuáles valen la inversión en general.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-theodore-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 6, $mbh$Mejores builds para Theodore$mbh$, $mbh$Abajo encontrarás las builds de árbol de talentos para Theodore que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos + algo de contexto adicional para cada build de talentos que muy probablemente apreciarás. Aquí tenemos, en general, la build de árbol de talentos más útil, que usarás para cualquier situación salvo Theodore en Garrison. Quieres aprovechar el Skill Tree aquí, ya que el Skill Tree es simplemente el árbol más fuerte de todos, y en muchas situaciones correría a Theodore como principal solo para aprovechar ese árbol, a menos que haya otras razones importantes. Los talentos de ahí son simplemente demasiado buenos y si sigues mi recomendación te divertirás con Theodore tanto como sea posible. Esta es la build de Garrison por si quieres apostarlo ahí. De nuevo, lo he señalado varias veces: no la recomiendo demasiado porque simplemente hay mejores héroes para eso, pero si no los tienes y quieres usar a Theodore, esta es sin duda la build que te recomiendo usar.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-theodore-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 7, $mbh$Conclusión$mbh$, $mbh$Espero que esta guía para construir a Theodore te haya ayudado a invertir sin perder mucho tiempo ni recursos. Si te gustó o tienes más preguntas (o quizás también anotaciones que creas que deberían añadirse aquí en esta guía), no dudes en publicarlas abajo en la sección de comentarios. Gracias por leer y que tengas un gran día.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-theodore-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  select id into hid from public.heroes where game_id=gid and slug=$mbh$ffraegar$mbh$;
  delete from public.hero_builds where hero_id=hid;
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 0, $mbh$Ranking actual – ¿es Ffraegar S-Tier, A-Tier o D-Tier?$mbh$, $mbh$Mira cómo se posiciona Ffraegar en los distintos modos de juego de Call of Dragons en mi tier list actual aquí, y asegúrate también de estar jugando con la mejor facción de Call of Dragons o podrías afectar tu progreso de forma muy negativa — tengo una guía actualizada sobre las mejores facciones de Call of Dragons aquí.

¡Importante! No te pierdas Gemas, Llaves, Boosters y Speedups gratis y revisa con frecuencia mi lista de códigos de regalo activos para Call of Dragons aquí.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-ffraegar-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 1, $mbh$Orden de habilidades$mbh$, $mbh$$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-ffraegar-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 2, $mbh$Mejores tipos de tropa$mbh$, $mbh$Hay dos formas de usar a Ffraegar: una es llevarla junto a otro héroe volador y usar unidades voladoras, lo cual es un setup de caza brutal. La otra es emparejarla con cualquier héroe buffer como Hosk y correr con unidades Marksman.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-ffraegar-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 3, $mbh$Mejores parejas de héroe para Ffraegar$mbh$, $mbh$Syndrion es, obviamente, una pareja perfecta ya que salieron juntos, ambos son Marksman y en general todas sus habilidades y talentos van de la mano. Al final, eso sí, te recomendaría usar a Syndrion como comandante principal de esta marcha (Ver build completa aquí).

Maggrat, por la forma en que escala los ataques normales y los críticos, funciona muy bien con ella (Ver build completa aquí).

Zayda, por la forma en que escala los ataques normales y los críticos, funciona muy bien con ella (Ver build completa aquí).

Hosk es una pareja fenomenal para Ffraegar ya que puede seguirle el ritmo a su altísimo alcance y potenciar la salida de daño, y con todos los críticos que ocurren en las habilidades de Ffraegar parecen un combo asesino (Ver build completa aquí).

Kinnara es también un excelente héroe Marksman que puedes emparejar con Ffraegar para ganar muchísima sinergia y volverte bastante loco también (Ver build completa aquí).

Nico parece una combinación perfecta porque también es un héroe Marksman, pero en realidad lo incluyo aquí más bien para advertirte: su habilidad activa tiene alcance medio (así que forzarías a Ffraegar, con su gran alcance, a un combate más cercano) y no puedes formar una marcha voladora. Podrías usarlo como marcha básica con Marksman, pero no lo recomendaría más allá de eso (Ver build completa aquí).

Theia es otra pareja natural con Ffraegar ya que ambas son héroes voladoras (puede que no lo notes de entrada, pero Ffraegar es una héroe de unidad voladora). Theia trabajará con el largo alcance de la habilidad activa de Ffraegar y hará que toda la marcha, llena de daño, sea mucho más sostenible (Ver build completa aquí).

Kregg puede ser una pareja viable al principio y, aunque es un héroe volador, le importa muy poco las unidades voladoras, así que aún puedes salir adelante con esa pareja (Ver build completa aquí).

Gwanwyn también puede funcionar, pero más allá de que ambas son héroes Marksman no hay mucha sinergia; aun así, si esa es tu única pareja posible, adelante (Ver build completa aquí).$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-ffraegar-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 4, $mbh$Mejores artefactos$mbh$, $mbh$Veamos ahora los numerosos artefactos que podrías usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las estadísticas, pero sin importar qué artefactos tengas disponibles, encontrarás el que mejor funcione. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Goldcrest es un artefacto Marksman increíble con Ffraegar y harás un daño impresionante usándolo, además el buff general a las unidades Marksman también es de otro mundo. Shadowblades es un artefacto Marksman increíble con Ffraegar y harás un daño impresionante usándolo, además el buff general a las unidades Marksman también es de otro mundo.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-ffraegar-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 5, $mbh$Mejores sinergias de mascota para Ffraegar (NUEVO)$mbh$, $mbh$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Ffraegar con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets de Call of Dragons aquí para ver cuáles valen la inversión en general.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-ffraegar-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 6, $mbh$Mejores builds para Ffraegar$mbh$, $mbh$Abajo encontrarás las builds de árbol de talentos para Ffraegar que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos + algo de contexto adicional para cada build de talentos que muy probablemente apreciarás. Este árbol es universal para todas las parejas cuando usas a Ffraegar junto a unidades voladoras para volar por encima del terreno y ser muy móvil. Idealmente quieres usarla con las unidades voladoras Wilderburg y su habilidad especial, pero también funciona bien con todas las demás unidades voladoras. Cuando emparejas a Ffraegar con Syndrion o sales a cazar legiones de magos, este es el árbol de talentos ideal para ello.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-ffraegar-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 7, $mbh$Conclusión$mbh$, $mbh$Espero que esta guía para construir a Ffraegar te haya ayudado a invertir sin perder mucho tiempo ni recursos. Si te gustó o tienes más preguntas (o quizás también anotaciones que creas que deberían añadirse aquí en esta guía), no dudes en publicarlas abajo en la sección de comentarios. Gracias por leer y que tengas un gran día.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-ffraegar-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
