  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 0, $mbh$Ranking actual – ¿es Syndrion S-Tier, A-Tier o D-Tier?$mbh$, $mbh$Mira cómo se posiciona Syndrion en los distintos modos de juego de Call of Dragons en mi tier list actual aquí, y asegúrate también de estar jugando con la mejor facción de Call of Dragons o podrías afectar tu progreso de forma muy negativa — tengo una guía actualizada sobre las mejores facciones de Call of Dragons aquí.

