  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 1, $mbh$Orden de habilidades$mbh$, $mbh$$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-syndrion-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 2, $mbh$Mejores tipos de tropa$mbh$, $mbh$Con la tercera habilidad de Syndrion y la forma en que funciona su kit, solo querrás usarlo con unidades Marksman exclusivamente.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-syndrion-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 3, $mbh$Mejores parejas de héroe para Syndrion$mbh$, $mbh$Ffraegar también potencia la probabilidad de crítico y el daño de los ataques normales, funciona muy bien con Syndrion y es la mejor pareja absoluta que puedes correr aquí para Marksman, e incluso de las mejores en general. Ambos se potencian tanto el uno al otro que, si corres su artefacto, les harás la vida imposible a todos (Ver build completa aquí).

Maggrat, por la forma en que escala los ataques normales y los críticos, funciona muy bien con él (Ver build completa aquí).

Zayda, por la forma en que escala los ataques normales y los críticos, funciona muy bien con él (Ver build completa aquí).

Hosk es una de las parejas importantes para Syndrion, ya que tienes el ataque extra que pega fuerte, así que quieres potenciar el daño de ataque normal, el crítico y la salida de daño tanto como sea posible; y como Hosk hace eso bien además de ser un héroe bastante universal, funciona genial con Syndrion (Ver build completa aquí).

Kinnara es también una pareja posible, aunque no me gusta tanto. La mayor sinergia aquí es que Kinnara aplica DEF break para que Syndrion haga más daño de ataque normal. No está mal, pero tampoco es tan destacable como las de arriba (Ver build completa aquí).

Gwanwyn tiene mucha sinergia con Syndrion ya que aplicará Poison con cada ataque normal, pero cambiar de objetivo no es perfecto y en general no es la mejor héroe. Aun así, si estás construyendo a Syndrion para tu segunda marcha Marksman y ya tienes a Nico y Kinnara en uso, es una opción viable, aunque no la gran cosa (Ver build completa aquí).

Nico es una pareja subóptima y no tienen mucha sinergia más allá de que Nico también es un héroe Marksman (Ver build completa aquí).$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-syndrion-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 4, $mbh$Mejores artefactos$mbh$, $mbh$Veamos ahora los numerosos artefactos que podrías usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las estadísticas, pero sin importar qué artefactos tengas disponibles, encontrarás el que mejor funcione. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Goldcrest es un artefacto Marksman increíble con Syndrion y harás un daño impresionante usándolo, además el buff general a las unidades Marksman también es de otro mundo. Mi favorito personal para usar con Syndrion si no lo corres con Ffraegar o no tienes Goldcrest disponible. Shadowblades es un artefacto Marksman increíble con Syndrion y harás un daño impresionante usándolo, además el buff general a las unidades Marksman también es de otro mundo. Mi favorito personal para usar con Syndrion si no lo corres con Ffraegar o no tienes Goldcrest disponible.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-syndrion-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 5, $mbh$Mejores sinergias de mascota para Syndrion (NUEVO)$mbh$, $mbh$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Syndrion con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets de Call of Dragons aquí para ver cuáles valen la inversión en general.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-syndrion-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 6, $mbh$Mejores builds para Syndrion$mbh$, $mbh$Abajo encontrarás las builds de árbol de talentos para Syndrion que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos + algo de contexto adicional para cada build de talentos que muy probablemente apreciarás. Esta es la build de talentos ideal que lo hace soltar daño normal de forma consistente al ritmo más alto; idealmente quieres emparejarlo con Ffraegar para esto.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-syndrion-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 7, $mbh$Conclusión$mbh$, $mbh$Espero que esta guía para construir a Syndrion te haya ayudado a invertir sin perder mucho tiempo ni recursos. Si te gustó o tienes más preguntas (o quizás también anotaciones que creas que deberían añadirse aquí en esta guía), no dudes en publicarlas abajo en la sección de comentarios. Gracias por leer y que tengas un gran día.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-syndrion-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  select id into hid from public.heroes where game_id=gid and slug=$mbh$liliya$mbh$;
  delete from public.hero_builds where hero_id=hid;
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 0, $mbh$Ranking actual – ¿es Liliya S-Tier, A-Tier o D-Tier?$mbh$, $mbh$Mira cómo se posiciona Liliya en los distintos modos de juego de Call of Dragons en mi tier list actual aquí, y asegúrate también de estar jugando con la mejor facción de Call of Dragons o podrías afectar tu progreso de forma muy negativa — tengo una guía actualizada sobre las mejores facciones de Call of Dragons aquí.

¡Importante! No te pierdas Gemas, Llaves, Boosters y Speedups gratis y revisa con frecuencia mi lista de códigos de regalo activos para Call of Dragons aquí.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-liliya-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 1, $mbh$Orden de habilidades$mbh$, $mbh$$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-liliya-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 2, $mbh$Mejores tipos de tropa$mbh$, $mbh$Usa todas Magic, o al menos tantas como sea posible, ya que potenciará el HP y el ataque de todas las unidades Magic de su legión a través de su tercera habilidad, y algunos de los puntos de talento que se muestran abajo también afectarán exclusivamente a las unidades Magic. No es obligatorio, pero ayudará mucho y te hará la vida más fácil al final del día.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-liliya-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 3, $mbh$Mejores parejas de héroe para Liliya$mbh$, $mbh$Velyn funciona increíblemente bien con Liliya en campo abierto ya que ambos giran en torno a las unidades Magic, y todos los buffs y debuffs que él aporta se aplicarán también a Liliya; y con la velocidad de marcha reducida de las legiones enemigas, las inmovilizarás y las rematarás de forma muy efectiva (Ver build completa aquí).

Waldyr tiene mucha sinergia de daño mágico con Liliya, y si no tienes a Velyn bien construido pero sí avanzaste bien con Waldyr, ambos pueden funcionar muy bien juntos en una legión (Ver build completa aquí).

Hosk es uno de los comandantes versátiles de Call of Dragons y muy versátil para usar junto a Liliya también, y ella se beneficiará mucho de los buffs que él proporciona con su primera y tercera habilidad (Ver build completa aquí).

Theia le dará a tu legión un escudo y, aunque no obtendrás todos sus buffs de habilidad activos, hace que tu legión de Liliya sea mucho más resistente, y como Liliya ya hace buen daño puede funcionar bien (Ver build completa aquí).

Bertrand puede funcionar, pero no hay demasiadas formas en que Bertrand pueda hacer estallar sus marcas aquí, y la combinación simplemente no está diseñada para trabajar junta a menos que sea un verdadero respaldo (Ver build completa aquí).

Alwyn funciona en muchos sentidos como la versión épica de Velyn y ayuda en campo abierto reduciendo la velocidad de marcha del objetivo, haciendo daño en el tiempo, buffeando unidades Magic y además haciendo muchísimo daño. La única desventaja es que esta legión puede volverse un poco glass-cannon ya que no tienes nada defensivo activo (Ver build completa aquí).

Atheus es también una pareja de comandante con Liliya para el combate en campo abierto, ya que obtienes daño de habilidad, rage adicional y además buffea la velocidad de marcha de todas las tropas (Ver build completa aquí).

Indis es la última de la lista aquí y la única razón por la que funcionan juntos es que el alcance de ataque de Indis también es muy largo. Una pareja muy de respaldo y no se estorban entre sí (Ver build completa aquí).$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-liliya-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 4, $mbh$Mejores artefactos$mbh$, $mbh$Veamos ahora los numerosos artefactos que podrías usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las estadísticas, pero sin importar qué artefactos tengas disponibles, encontrarás el que mejor funcione. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Phoenix Eye puede curar a tus unidades y aumenta las estadísticas base de las unidades Magic. Es un artefacto útil para correr con Liliya si la llevas junto a otro héroe que haga daño, así ganas algo de supervivencia. Tear of Arbon puede curar a tus unidades y aumenta las estadísticas base de las unidades Magic. Es un artefacto útil para correr con Liliya si la llevas junto a otro héroe que haga daño, así ganas algo de supervivencia.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-liliya-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 5, $mbh$Mejores sinergias de mascota para Liliya (NUEVO)$mbh$, $mbh$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Liliya con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets de Call of Dragons aquí para ver cuáles valen la inversión en general.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-liliya-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 6, $mbh$Mejores builds para Liliya$mbh$, $mbh$Abajo encontrarás las builds de árbol de talentos para Liliya que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos + algo de contexto adicional para cada build de talentos que muy probablemente apreciarás. Este es el árbol de talentos que usarías con Liliya en 2024 en aproximadamente el 95% de los casos. Funciona con todos los héroes Magic con los que la emparejes y es el mejor tanto en PvE como en PvP. La única excepción es cuando la usas con Tohar, entonces no querrás usar este árbol (ver abajo). Como mencioné arriba, este es el árbol de talentos que quieres usar cuando la emparejas con héroes que aplican efectos de buff (especialmente con Tohar, pero también héroes como Hosk y Theia tienden a funcionar mejor con ese árbol). Estos dos son los únicos árboles válidos para Liliya hoy en día, y si ves fuentes mostrando otros árboles, bueno, están muy desactualizados de mediados de 2023, así que no los uses más.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-liliya-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 7, $mbh$Conclusión$mbh$, $mbh$Espero que esta guía para construir a Liliya te haya ayudado a invertir sin perder mucho tiempo ni recursos. Si te gustó o tienes más preguntas (o quizás también anotaciones que creas que deberían añadirse aquí en esta guía), no dudes en publicarlas abajo en la sección de comentarios. Gracias por leer y que tengas un gran día.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-liliya-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
