  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 0, $mbh$Ranking actual – ¿es Nico S-Tier, A-Tier o D-Tier?$mbh$, $mbh$Mira cómo se posiciona Nico en los distintos modos de juego de Call of Dragons en mi tier list actual aquí, y asegúrate también de estar jugando con la mejor facción de Call of Dragons o podrías afectar tu progreso de forma muy negativa — tengo una guía actualizada sobre las mejores facciones de Call of Dragons aquí.

¡Importante! No te pierdas Gemas, Llaves, Boosters y Speedups gratis y revisa con frecuencia mi lista de códigos de regalo activos para Call of Dragons aquí.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-nico-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 1, $mbh$Orden de habilidades$mbh$, $mbh$$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-nico-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 2, $mbh$Mejores tipos de tropa$mbh$, $mbh$Con todos los talentos y su tercera habilidad, recomiendo correr a Nico solo con unidades Marksman para ser lo más efectivo posible. Además, como las unidades Marksman tienen un alcance tan corto (comparado con las unidades de magos), a menudo empiezan haciendo off-tank y soltando daño de contraataque activo.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-nico-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 3, $mbh$Mejores parejas de héroe para Nico$mbh$, $mbh$Kinnara es, sin lugar a dudas, la mejor combinación junto a Nico; harás cantidades increíbles de daño, y con Nico como héroe principal puedes infligir el DEF break con su habilidad activa, y entonces el suyo con Kinnara pega mucho más fuerte. Alternativamente, puedes considerar correr a Kinnara principal para poder tener activo el Control Tree, pero querrás a Nico con expertise, ya que puedes usar Ambush en el Control Tree para tener prácticamente siempre la oportunidad de infligir DEF break, y entonces Nico hará sus 200 de daño extra (Ver build completa aquí).

Hosk funciona genial (pero en realidad puedes emparejarlo con cualquier héroe en Call of Dragons). Solo digo que funciona bien porque solo está disponible para grandes gastadores en las etapas tempranas de Call of Dragons, ya que solo puedes conseguirlo a través de la Honour Store con VIP Level 10+. Funciona de maravilla, ya que buffea prácticamente todo lo que hace Nico, pero requiere, como dije, una inversión bastante alta, incluyendo subir su tercera y cuarta habilidad. En un mundo perfecto diría que Hosk es el mejor encaje para Nico (Ver build completa aquí).

Theia es una opción válida PERO SOLO si usas Wilderburg como tu facción para tener los jinetes voladores que activarán la tercera habilidad de Theia. Si NO corres esa facción, ¡ni se te ocurra emparejar a Theia con Nico! (Ver build completa aquí).

Ffraegar funciona y tiene mucha sinergia, pero hay un gran problema que no me gusta aquí, y es la diferencia de alcances: Nico fuerza a Ffraegar, con su altísimo alcance, a un alcance medio, lo cual no aprecio mucho y veo casos mucho mejores. Aparte de eso, y por la forma en que funcionan sus kits, aún van bien juntos (Ver build completa aquí).

Gwanwyn es una gran pareja de early-game, ya que puedes subirla de nivel fácilmente, comparten la sinergia Marksman y simplemente van muy bien juntos. Cuanto más mejores a Nico, más querrás usarlo como héroe principal de la legión. Con el daño añadido contra Darklings y Dark Legions, esta es más bien una pareja de early-game, eso sí (Ver build completa aquí).

Kregg es también una pareja F2P muy buena con Nico, también de Marksman y con el daño en área. Te pierdes la sinergia de unidades Flying a menos que corras Wilderburg como tu facción. Si lo haces, preferiría a Kregg sobre Gwanwyn en cualquier momento (Ver build completa aquí).

Syndrion solo tiene la sinergia de que ambos corren y funcionan con Marksman, y en realidad no hay una sinergia más profunda (Ver build completa aquí).$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-nico-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 4, $mbh$Mejores artefactos$mbh$, $mbh$Veamos ahora los numerosos artefactos que podrías usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las estadísticas, pero sin importar qué artefactos tengas disponibles, encontrarás el que mejor funcione. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Shadowblades también funciona genial con Nico, pero eso es porque es un artefacto Marksman increíble en general. Aun así, en términos globales no lo recomendaría y veo mejores opciones para este artefacto, pero cuando solo miras a Nico es una elección increíble. Rattle Spear también funciona genial con Nico, pero eso es porque es un artefacto Marksman increíble en general. Aun así, en términos globales no lo recomendaría y veo mejores opciones para este artefacto, pero cuando solo miras a Nico es una elección increíble.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-nico-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 5, $mbh$Mejores sinergias de mascota para Nico (NUEVO)$mbh$, $mbh$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Nico con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets de Call of Dragons aquí para ver cuáles valen la inversión en general.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-nico-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 6, $mbh$Mejores builds para Nico$mbh$, $mbh$Abajo encontrarás las builds de árbol de talentos para Nico que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos + algo de contexto adicional para cada build de talentos que muy probablemente apreciarás. Déjame aclarar un par de cosas antes de entrar en los árboles de talentos. Abajo ves los árboles de talentos que funcionan con Nico, también en temporadas posteriores. Muchas, casi todas, las fuentes que tienen árboles de talentos los crearon en la primavera de 2024 cuando salió Call of Dragons y nunca más los tocaron. Pero las season skills, los héroes adicionales y el meta cambiaron con ello. Así que los árboles de abajo son los que funcionan a finales de 2024, y si ves otros árboles de talentos por ahí, están desactualizados... Así que este primer árbol de talentos es para potenciar el daño de ataque normal de Marksman con cualquier otro héroe Marksman que no use principalmente daño de habilidad, y funciona bastante bien en todas las partes donde usarías a Nico. Este árbol de talentos se usa mejor con tropas Marksman T4 junto a las habituales parejas secundarias de héroe Marksman para contrarrestar y cazar legiones de magos. Esta build de talentos es principalmente para contenido PvE, en particular para hacer raid a Behemoths, donde te ayudará a soltar el máximo daño posible.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-nico-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 7, $mbh$Conclusión$mbh$, $mbh$Espero que esta guía para construir a Nico te haya ayudado a invertir sin perder mucho tiempo ni recursos. Si te gustó o tienes más preguntas (o quizás también anotaciones que creas que deberían añadirse aquí en esta guía), no dudes en publicarlas abajo en la sección de comentarios. Gracias por leer y que tengas un gran día.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-nico-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  select id into hid from public.heroes where game_id=gid and slug=$mbh$nika$mbh$;
  delete from public.hero_builds where hero_id=hid;
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 0, $mbh$Ranking actual – ¿es Nika S-Tier, A-Tier o D-Tier?$mbh$, $mbh$Mira cómo se posiciona Nika en los distintos modos de juego de Call of Dragons en mi tier list actual aquí, y asegúrate también de estar jugando con la mejor facción de Call of Dragons o podrías afectar tu progreso de forma muy negativa — tengo una guía actualizada sobre las mejores facciones de Call of Dragons aquí.

¡Importante! No te pierdas Gemas, Llaves, Boosters y Speedups gratis y revisa con frecuencia mi lista de códigos de regalo activos para Call of Dragons aquí.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-nika-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 1, $mbh$Orden de habilidades$mbh$, $mbh$$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-nika-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 2, $mbh$Mejores tipos de tropa$mbh$, $mbh$Usa todas las unidades de Infantry, o al menos tantas como sea posible, ya que potenciará el HP y el ataque de todas las unidades de Infantry de su legión a través de su tercera habilidad, y algunos de los puntos de talento que se muestran abajo también afectarán exclusivamente a las unidades de Infantry. No es obligatorio, pero ayudará mucho y te hará la vida más fácil al final del día.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-nika-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 3, $mbh$Mejores parejas de héroe para Nika$mbh$, $mbh$Madeline es, junto a Nika, probablemente el combo de Infantry más fuerte que puedes correr ahora mismo, y como Madeline también hace algo de daño de habilidad, el buff de la cuarta habilidad de Nika no se desperdicia. Eso sí, querrás considerar correr a Madeline como comandante principal en esto, a menos que tengas a tu Nika mucho más desarrollada que a tu Madeline (Ver build completa aquí).

Hosk es un héroe universalmente genial en Call of Dragons y no le importa mucho el tipo de tropa. Quieres correr a Nika como comandante principal aquí para poder usar su Infantry Tree. No es el combo más tanque para pelear por ahí, pero es súper castigador y hace muchísimo daño sin dejar de ser bastante versátil. Entiendo que solo un pequeño porcentaje de jugadores puede correr esto, pero es simplemente una pareja clavada, así que la tengo listada aquí (Ver build completa aquí).

Bakhar es una gran pareja épica, pero hay un poco más que eso. En realidad quieres correrlo como comandante principal para acumular el daño que hacen sus unidades con su habilidad activa, y luego puedes golpearlos con el gran daño de habilidad de Nika (Ver build completa aquí).

Theia es una pareja bastante astuta, y con Nika como comandante principal en este combo ganas el escudo de Theia para más sustain en el campo, y Theia buffeará aún más el sólido daño de habilidad que hace Nika. Te perderás los beneficios de unidad voladora, pero eso en realidad está bien en este setup (Ver build completa aquí).

Garwood es un héroe tan durable en Call of Dragons y su kit en realidad apunta más a ser tan durable que derribas enemigos con contraataques mientras ellos básicamente no le bajan mucho su pool; y con el enfoque más ofensivo y el daño de habilidad que hace Nika, siento que este es un setup mediocre (Ver build completa aquí).

Eliana funciona como pareja básica, ya que puedes esconder a Eliana como comandante épica detrás de Nika y entonces ganar escudo y hacer que Nika funcione un poco mejor por el lado resistente. De nuevo, esta es una pareja de etapa temprana y no una que quieras correr demasiado tiempo (Ver build completa aquí).$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-nika-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 4, $mbh$Mejores artefactos$mbh$, $mbh$Veamos ahora los numerosos artefactos que podrías usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las estadísticas, pero sin importar qué artefactos tengas disponibles, encontrarás el que mejor funcione. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Dragon Scale Armor aumenta la defensa de la legión de Nika y es un artefacto absolutamente impresionante (sin juego de palabras) para correr con Nika pase lo que pase. La disponibilidad de este artefacto es otra discusión, eso sí... Greymar's Warhammer aumenta la defensa de la legión de Nika y es un artefacto absolutamente impresionante (sin juego de palabras) para correr con Nika pase lo que pase. La disponibilidad de este artefacto es otra discusión, eso sí...$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-nika-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 5, $mbh$Mejores sinergias de mascota para Nika (NUEVO)$mbh$, $mbh$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Nika con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets de Call of Dragons aquí para ver cuáles valen la inversión en general.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-nika-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 6, $mbh$Mejores builds para Nika$mbh$, $mbh$Abajo encontrarás las builds de árbol de talentos para Nika que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos + algo de contexto adicional para cada build de talentos que muy probablemente apreciarás. Este es uno de los dos setups de árbol de talentos que funcionan con Nika, y usándola junto a un héroe que haga daño de contraataque o potencie el daño de contraataque, este es el árbol de talentos que quieres usar sin importar si empezaste a jugar ayer o hace un año. Este árbol de talentos se centra más en usar a Nika como tanque y hacer daño de habilidad, así que si la emparejas con cualquier héroe que sí haga daño de habilidad y no tenga habilidades de contraataque (desbloqueadas), este es tu árbol de talentos de elección.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-nika-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
