  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 2, $mbh$Mejores tipos de tropa$mbh$, $mbh$Es una héroe general y de apoyo, así que los tipos de tropa no importan, e incluso el tamaño no importa si la usas para una legión de apoyo; para gathering, lleva lo que necesites para recolectar.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-indis-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 3, $mbh$Mejores parejas de héroe para Indis$mbh$, $mbh$Emrys forma una pareja bastante buena con Indis, ya que puedes usarlo para lanzarte a las batallas, rodeando legiones enemigas para el daño extra, y con Indis tienes curación, más daño y debuffeo del enemigo en marcha, lo que lo hace mucho más sostenible (Ver build completa aquí).

Garwood sería una pareja para una marcha de sustain increíble si corres una pelea que requiera una legión tanque aguantando el mayor tiempo posible. Tendrán muchísima curación y la limpieza de debuffs de Indis es muy útil en ese punto (Ver build completa aquí).

Liliya o cualquier otro héroe de magos puede funcionar con Indis también, ya que ganas el daño aumentado y otros rasgos al correrla como legión secundaria. Solo úsalo si no haces multi-legión, porque entonces normalmente tienes una legión tanque que recibe el daño, así que la legión de Liliya no será necesariamente el objetivo y más bien querrás un deputy de magos para hacer daño (Ver build completa aquí).$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-indis-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 4, $mbh$Mejores artefactos$mbh$, $mbh$Veamos ahora los numerosos artefactos que podrías usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las estadísticas, pero sin importar qué artefactos tengas disponibles, encontrarás el que mejor funcione. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Lucias Horn: más capacidad de carga y HP siempre funciona en tu legión de gathering, y aquí funciona genial también. Greenfinger Sickle: más capacidad de carga y HP siempre funciona en tu legión de gathering, y aquí funciona genial también.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-indis-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 5, $mbh$Mejores sinergias de mascota para Indis (NUEVO)$mbh$, $mbh$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Indis con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets de Call of Dragons aquí para ver cuáles valen la inversión en general.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-indis-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 6, $mbh$Mejores builds para Indis$mbh$, $mbh$Abajo encontrarás las builds de árbol de talentos para Indis que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos + algo de contexto adicional para cada build de talentos que muy probablemente apreciarás. Antes que nada, y sé que mucha gente no quiere oír esto ya que pueden construir una Indis legendaria sin gastar un duro, ella es una héroe de gathering. Sí, puedes usarla potencialmente para algo de apoyo, pero rinde mejor como héroe de gathering. Y esta es la build de talentos que deberías usar para eso. Si buscas correrla como héroe de apoyo para héroes Marksman, esta es la build de talentos que deberías usar. Si buscas correrla como héroe de apoyo para héroes de magos, esta es la build de talentos que deberías usar.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-indis-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
