  values (hid, 5, $mbh$Mejores sinergias de mascota para Alistair (NUEVO)$mbh$, $mbh$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Alistair con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets de Call of Dragons aquí para ver cuáles valen la inversión en general.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-alistair-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 6, $mbh$Mejores builds para Alistair$mbh$, $mbh$Abajo encontrarás las builds de árbol de talentos para Alistair que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos + algo de contexto adicional para cada build de talentos que muy probablemente apreciarás. Hoy en día Alistair se usa principalmente para legiones de Cavalry adicionales con muchísima velocidad, así que a menos que lo uses en un servidor nuevo en los primeros días, esta build de talentos de velocidad es la que quieres usar con él.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-alistair-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
