  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified)
  values (hid, 6, $mbh$Mejores builds para Eliana$mbh$, $mbh$Abajo encontrarás las builds de árbol de talentos para Eliana que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos + algo de contexto adicional para cada build de talentos que muy probablemente apreciarás. Para mí, el único caso de uso donde realmente usarías a Eliana como comandante principal es cuando estás al principio en un servidor nuevo, acabas de sacar a Garwood y buscas una formación defensiva con muchísima curación sin tener que invertir demasiado en Garwood (todavía). Ahí es cuando quieres correr a Eliana como comandante principal de tu legión con este árbol de talentos.$mbh$, '{}'::text[], $mbh$https://www.allclash.com/best-eliana-builds-talent-tree-skill-order-best-pairing-in-call-of-dragons/$mbh$, false);
